pub struct OAuthApi {
	http: Arc<HttpClient>,
}

impl OAuthApi {
	pub(crate) fn new(http: Arc<HttpClient>) -> Self {
		Self { http }
	}

	/// Get Access Token
	pub async fn token(
		&self,
		body: Option<&OAuthTokenBody>,
	) -> Result<OAuthTokenResponse, LolzteamError> {
		let mut parts = Vec::new();
		if let Some(b) = body {
			match b {
				OAuthTokenBody::ClientCredentials {
					client_id,
					client_secret,
					scope,
				} => {
					parts.push(MultipartPart::Text {
						name: "grant_type".to_string(),
						value: "client_credentials".to_string(),
					});
					parts.push(MultipartPart::Text {
						name: "client_id".to_string(),
						value: client_id.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "client_secret".to_string(),
						value: client_secret.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "scope".to_string(),
						value: scope
							.iter()
							.map(|v| v.to_string())
							.collect::<Vec<_>>()
							.join(" "),
					});
				}
				OAuthTokenBody::AuthorizationCode {
					client_id,
					client_secret,
					code,
					redirect_uri,
					scope,
				} => {
					parts.push(MultipartPart::Text {
						name: "grant_type".to_string(),
						value: "authorization_code".to_string(),
					});
					parts.push(MultipartPart::Text {
						name: "client_id".to_string(),
						value: client_id.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "client_secret".to_string(),
						value: client_secret.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "code".to_string(),
						value: code.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "redirect_uri".to_string(),
						value: redirect_uri.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "scope".to_string(),
						value: scope
							.iter()
							.map(|v| v.to_string())
							.collect::<Vec<_>>()
							.join(" "),
					});
				}
				OAuthTokenBody::RefreshToken {
					client_id,
					client_secret,
					refresh_token,
				} => {
					parts.push(MultipartPart::Text {
						name: "grant_type".to_string(),
						value: "refresh_token".to_string(),
					});
					parts.push(MultipartPart::Text {
						name: "client_id".to_string(),
						value: client_id.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "client_secret".to_string(),
						value: client_secret.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "refresh_token".to_string(),
						value: refresh_token.clone(),
					});
				}
				OAuthTokenBody::Password {
					client_id,
					client_secret,
					password,
					scope,
					username,
				} => {
					parts.push(MultipartPart::Text {
						name: "grant_type".to_string(),
						value: "password".to_string(),
					});
					parts.push(MultipartPart::Text {
						name: "client_id".to_string(),
						value: client_id.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "client_secret".to_string(),
						value: client_secret.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "password".to_string(),
						value: password.clone(),
					});
					parts.push(MultipartPart::Text {
						name: "scope".to_string(),
						value: scope
							.iter()
							.map(|v| v.to_string())
							.collect::<Vec<_>>()
							.join(" "),
					});
					parts.push(MultipartPart::Text {
						name: "username".to_string(),
						value: username.clone(),
					});
				}
			}
		}
		self.http
			.request_multipart("POST", "/oauth/token", parts, false)
			.await
	}
}

